--- index.html ---
<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Lab Technician - Professional Services</title>
  <link rel="stylesheet" href="styles.css" />
  <script src="script.js" defer></script>
</head>
<body>
  <header class="hero" role="banner">
    <div class="container">
      <h1 id="hero-title">Professional Lab Technician</h1>
      <p class="subtitle">Reliable lab support with a focus on precision, safety, and efficiency.</p>
    </div>
  </header>

  <main id="main" class="main" role="main">
    <section id="services" class="section services" aria-labelledby="services-title">
      <div class="container">
        <h2 id="services-title">Services</h2>
        <ul class="service-list">
          <li>Sample preparation and handling</li>
          <li>Equipment calibration and maintenance</li>
          <li>Data recording and quality control</li>
        </ul>
      </div>
    </section>

    <section id="contact" class="section contact" aria-labelledby="contact-title">
      <div class="container">
        <h2 id="contact-title">Contact</h2>
        <form id="contact-form" class="contact-form" novalidate>
          <div class="form-row">
            <label for="name">Name</label>
            <input type="text" id="name" name="name" placeholder="Your name" autocomplete="name" required />
          </div>
          <div class="form-row">
            <label for="email">Email</label>
            <input type="email" id="email" name="email" placeholder="you@example.com" autocomplete="email" required />
          </div>
          <div class="form-row">
            <label for="message">Message</label>
            <textarea id="message" name="message" rows="4" placeholder="How can I help you?" required></textarea>
          </div>
          <button type="submit" class="btn">Send Message</button>
        </form>
      </div>
    </section>
  </main>

  <footer class="footer" role="contentinfo">
    <div class="container">
      <p>&copy; <span id="year"></span> Lab Technician</p>
    </div>
  </footer>

  <script>
    document.getElementById('year').textContent = new Date().getFullYear();
  </script>
</body>
</html>


