--- script.js ---
document.addEventListener('DOMContentLoaded', () => {
  const form = document.getElementById('contact-form');
  if (form) {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const nameEl = document.getElementById('name');
      const nameVal = nameEl && 'value' in nameEl ? nameEl.value.trim() : '';
      alert(`Thank you${nameVal ? ', ' + nameVal : ''}! Your message has been received.`);
      form.reset();
    });
  }
});


--- styles.css ---
/* Color palette: red (#d00000), black (#000), white (#fff) */
* { box-sizing: border-box; }
html, body { height: 100%; }
body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, Arial, sans-serif;
  color: #000;
  background: #fff;
  line-height: 1.5;
}
.container { width: min(960px, 92%); margin: 0 auto; }

.hero {
  background: #000;
  color: #fff;
  padding: 4rem 0 3.5rem;
  text-align: center;
  border-bottom: 4px solid #d00000;
}
.hero .subtitle {
  color: #fff;
  max-width: 60ch;
  margin: 0.5rem auto 0;
}

h1, h2, h3 { margin: 0 0 0.5rem; line-height: 1.2; }
p { margin: 0.5rem 0 0; }

.main { padding: 2rem 0 3rem; }
.section { padding: 2rem 0; }

/* Services */
.services h2 { border-left: 6px solid #d00000; padding-left: 0.5rem; }
.service-list {
  list-style: none;
  padding: 0;
  margin: 1rem 0 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 0.75rem 1rem;
}
.service-list li {
  border: 1px solid #000;
  padding: 0.75rem 0.75rem;
  border-left: 6px solid #d00000;
  background: #fff;
}

/* Contact */
.contact h2 { border-left: 6px solid #d00000; padding-left: 0.5rem; }
.contact-form { margin-top: 1rem; }
.form-row { display: flex; flex-direction: column; margin-bottom: 0.75rem; }
label { font-weight: 600; margin-bottom: 0.25rem; }
input, textarea {
  appearance: none;
  border: 1px solid #000;
  padding: 0.6rem 0.65rem;
  font: inherit;
  color: #000;
  background: #fff;
}
input:focus, textarea:focus { outline: 2px solid #d00000; outline-offset: 1px; }

.btn {
  display: inline-block;
  border: 0;
  background: #d00000;
  color: #fff;
  padding: 0.7rem 1rem;
  font-weight: 700;
  cursor: pointer;
}
.btn:focus { outline: 2px solid #000; outline-offset: 2px; }
.btn:hover { filter: brightness(0.9); }

.footer {
  border-top: 4px solid #d00000;
  padding: 1rem 0;
  text-align: center;
}

@media (min-width: 768px) {
  .hero { padding: 5rem 0 4rem; }
}

